function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      (entries) => entries.forEach((e) => e.isIntersecting && setVisible(true)),
      { threshold: 0.15 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function InteractiveBackground() {
  const canvasRef = useRef(null);
  const mouse = useRef({ x: -9999, y: -9999 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let width, height, particles, raf;

    function resize() {
      width = canvas.offsetWidth;
      height = canvas.offsetHeight;
      canvas.width = width * devicePixelRatio;
      canvas.height = height * devicePixelRatio;
      ctx.scale(devicePixelRatio, devicePixelRatio);
    }

    function init() {
      const count = Math.max(30, Math.floor((width * height) / 26000));
      particles = Array.from({ length: count }, () => ({
        x: Math.random() * width,
        y: Math.random() * height,
        vx: (Math.random() - 0.5) * 0.25,
        vy: (Math.random() - 0.5) * 0.25,
        r: Math.random() * 1.4 + 0.6,
      }));
    }

    function step() {
      ctx.clearRect(0, 0, width, height);
      for (const p of particles) {
        p.x += p.vx;
        p.y += p.vy;
        if (p.x < 0 || p.x > width) p.vx *= -1;
        if (p.y < 0 || p.y > height) p.vy *= -1;

        const dx = p.x - mouse.current.x;
        const dy = p.y - mouse.current.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 90) {
          p.x += dx * 0.004;
          p.y += dy * 0.004;
        }
      }
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const a = particles[i], b = particles[j];
          const dx = a.x - b.x, dy = a.y - b.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 120) {
            ctx.strokeStyle = `rgba(207,244,58,${0.14 * (1 - dist / 120)})`;
            ctx.lineWidth = 0.6;
            ctx.beginPath();
            ctx.moveTo(a.x, a.y);
            ctx.lineTo(b.x, b.y);
            ctx.stroke();
          }
        }
      }
      for (const p of particles) {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(207,244,58,0.55)";
        ctx.fill();
      }
      raf = requestAnimationFrame(step);
    }

    function onMove(e) {
      const rect = canvas.getBoundingClientRect();
      mouse.current.x = e.clientX - rect.left;
      mouse.current.y = e.clientY - rect.top;
    }
    function onLeave() {
      mouse.current.x = -9999;
      mouse.current.y = -9999;
    }

    resize();
    init();
    step();
    window.addEventListener("resize", () => { resize(); init(); });
    canvas.addEventListener("mousemove", onMove);
    canvas.addEventListener("mouseleave", onLeave);
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
      canvas.removeEventListener("mousemove", onMove);
      canvas.removeEventListener("mouseleave", onLeave);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="absolute inset-0 w-full h-full pointer-events-auto"
      style={{ zIndex: 0 }}
    />
  );
}

function Reveal({ children, className = "" }) {
  const [ref, visible] = useReveal();
  return (
    <div
      ref={ref}
      className={`transition-all duration-700 ease-out ${
        visible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-6"
      } ${className}`}
    >
      {children}
    </div>
  );
}

const LEMONSQUEEZY_STORE = "building-above-average";
const THANK_YOU_URL = "https://buildingaboveaverage.com/thank-you-newsletter";

function NewsletterForm({ variant = "outline", label = "Join free", theme = "dark", rounded = false }) {
  const [email, setEmail] = useState("");
  const [status, setStatus] = useState("idle"); // idle | loading | done | error

  const buttonStyles = {
    outline: { backgroundColor: "transparent", border: "1px solid #CFF43A", color: "#CFF43A" },
    solid: { backgroundColor: "#1E1E1C", color: "#CFF43A", border: "none" },
    outlineLight: { backgroundColor: "transparent", border: "1px solid #1E1E1C", color: "#1E1E1C" },
    outlineDark: { backgroundColor: "transparent", border: "1px solid #3a3a35", color: "#F6F2E9" },
    lime: { backgroundColor: "#CFF43A", color: "#1E1E1C", border: "none" },
  };

  async function handleSubmit(e) {
    e.preventDefault();
    if (!email) return;
    setStatus("loading");
    try {
      const formData = new FormData();
      formData.append("email", email);
      const res = await fetch(`https://${LEMONSQUEEZY_STORE}.lemonsqueezy.com/email-subscribe/external`, {
        method: "POST",
        body: formData,
      });
      if (!res.ok) throw new Error("failed");
      setStatus("done");
      window.location.href = THANK_YOU_URL;
    } catch (err) {
      setStatus("error");
    }
  }

  if (status === "done") {
    return <p className="text-xs" style={{ color: "#CFF43A" }}>Check your inbox — you're in.</p>;
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-2 w-full">
      <input
        type="email"
        required
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        placeholder="you@email.com"
        className={`flex-1 text-sm px-4 py-3 bg-transparent border outline-none ${theme === "light" ? "input-light" : "input-dark"} ${rounded ? "rounded-full" : ""}`}
        style={theme === "light" ? { borderColor: "#d8d2c2" } : { borderColor: "#3a3a35" }}
      />
      <button
        type="submit"
        disabled={status === "loading"}
        className={`text-sm font-semibold uppercase tracking-wide px-6 py-3 transition-opacity hover:opacity-90 whitespace-nowrap ${rounded ? "rounded-full" : ""}`}
        style={buttonStyles[variant]}
      >
        {status === "loading" ? "Joining…" : label}
      </button>
      {status === "error" && (
        <p className="text-xs w-full" style={{ color: "#e08a8a" }}>Something went wrong, try again.</p>
      )}
    </form>
  );
}

